    hundreds_list = ["", "onehundred", "twohundred", "threehundred", "fourhundred", "fivehundred", 
                     "sixhundred", "sevenhundred", "eighthundred", "ninehundred"]

    if n <= 19:
        return ones[n]
    elif n < 100:
        t = n // 10
        o = n % 10
        return tens_list[t] + ones[o]
    else:
        h = n // 100
        rest = n % 100
        if rest != 0:
            return hundreds_list[h] + spell_number(rest)
        else:
            return hundreds_list[h]

