def solve():
    a, b, f, k = map(int, input().split())

    fuel = b
    refuels = 0

    # Move from start (x=0) to first checkpoint (x=f)
    fuel -= f
    if fuel < 0:
        print(-1)
        return

    for i in range(1, k + 1):
        # Compute distance from checkpoint i to next event
        if i < k:
            if i % 2 == 1:
                d = 2 * (a - f)  # Journey i is 0→a: go to a, then back to f
            else:
                d = 2 * f        # Journey i is a→0: go to 0, then back to f
        else:
            # Last checkpoint to end
            if k % 2 == 1:
                d = a - f  # Last journey 0→a: f to a
            else:
                d = f      # Last journey a→0: f to 0

        if fuel < d:
            fuel = b
            refuels += 1
            if fuel < d:
                print(-1)
                return

        fuel -= d

    print(refuels)

