from math import comb

def count_with_k_bits_up_to(x, k):
    """Count integers in [0, x] with exactly k set bits."""
    if x < 0 or k < 0:
        return 0
    result = 0
    ones = 0
    for bit in range(63, -1, -1):
        if x & (1 << bit):
            remaining_bits = bit
            remaining_needed = k - ones
            if 0 <= remaining_needed <= remaining_bits:
                result += comb(remaining_bits, remaining_needed)
            ones += 1
            if ones > k:
                break
    if ones == k:
        result += 1
    return result

def f(n, k):
    """Count numbers in [n+1, 2n] with exactly k set bits."""
    return count_with_k_bits_up_to(2 * n, k) - count_with_k_bits_up_to(n, k)

def solve():
    m, k = map(int, input().split())

