import sys

def main():
    data = sys.stdin.buffer.read().split()
    idx = 0
    N = int(data[idx]); idx += 1

    MAX_ING = 500001
    parent = list(range(MAX_ING))
    size = [1] * MAX_ING
    used = [False] * MAX_ING

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def union(x, y):
        rx, ry = find(x), find(y)
        if rx == ry:
            return
        if size[rx] < size[ry]:
            rx, ry = ry, rx
        parent[ry] = rx
        size[rx] += size[ry]

    count = 0

    for _ in range(N):
        M = int(data[idx]); idx += 1
        ingredients = [int(data[idx + j]) for j in range(M)]
        idx += M

        # Check if we can concoct this recipe
        can_concoct = True
        comp_count = {}

        for i in ingredients:
            if used[i]:
                r = find(i)
                comp_count[r] = comp_count.get(r, 0) + 1

        for r, cnt in comp_count.items():
            if size[r] != cnt:
                can_concoct = False
                break

        if can_concoct:
            count += 1
            for i in ingredients:
                used[i] = True
            for i in range(1, M):
                union(ingredients[0], ingredients[i])

    print(count)

