def solve():
    N = int(input())
    A = []
    for _ in range(N):
        row = list(map(int, input().split()))
        A.append(row)

    # Verify diagonal is 0
    for i in range(N):
        if A[i][i] != 0:
            print(-1)
            return

    # Verify symmetry
    for i in range(N):
        for j in range(N):
            if A[i][j] != A[j][i]:
                print(-1)
                return

    # Verify triangle inequality
    for i in range(N):
        for j in range(N):
            for k in range(N):
                if A[i][j] > A[i][k] + A[k][j]:
                    print(-1)
                    return

    # Find necessary edges
    total = 0
    for i in range(N):
        for j in range(i+1, N):
            necessary = True
            for k in range(N):
                if k != i and k != j:
                    if A[i][k] + A[k][j] == A[i][j]:
                        necessary = False
                        break
            if necessary:
                total += A[i][j]

    print(total)

