def find_mth_valid_permutation(available, m):
    if not available:
        return []
    if len(available) == 1:
        return list(available)

    k = len(available)
    half = 2 ** (k - 2)

    a1 = available[0]
    rest = available[1:]

    if m <= half:
        return [a1] + find_mth_valid_permutation(rest, m)
    else:
        return find_mth_valid_permutation(rest, m - half) + [a1]

