import sys

def solve():
    data = sys.stdin.read().split()
    idx = 0
    n = int(data[idx]); idx += 1
    grid = []
    for i in range(n):
        row = [int(data[idx+j]) for j in range(n)]
        idx += n
        grid.append(row)

    if n == 1:
        print(1)
        return

    # Find empty cell
    r, c = -1, -1
    for i in range(n):
        for j in range(n):
            if grid[i][j] == 0:
                r, c = i, j
                break
        if r != -1:
            break

    # Compute row sums and col sums
    row_sums = [sum(grid[i]) for i in range(n)]
    col_sums = [sum(grid[i][j] for i in range(n)) for j in range(n)]

    # Determine target from a complete row
    target = None
    for i in range(n):
        if i != r:
            target = row_sums[i]
            break

    # Verify all complete rows
    for i in range(n):
        if i != r and row_sums[i] != target:
            print(-1)
            return

    # Verify all complete columns
    for j in range(n):
        if j != c and col_sums[j] != target:
            print(-1)
            return

    # Compute x
    x = target - row_sums[r]

    # Verify column c
    if col_sums[c] + x != target:
        print(-1)
        return

    # Check x > 0
    if x <= 0:
        print(-1)
        return

    # Check main diagonal
    main_diag_sum = sum(grid[i][i] for i in range(n))
    if r == c:
        if main_diag_sum + x != target:
            print(-1)
            return
    else:
        if main_diag_sum != target:
            print(-1)
            return

    # Check secondary diagonal
    sec_diag_sum = sum(grid[i][n-1-i] for i in range(n))
    if r + c == n - 1:
        if sec_diag_sum + x != target:
            print(-1)
            return
    else:
        if sec_diag_sum != target:
            print(-1)
            return

    print(x)

