import sys
from bisect import bisect_right

def solve():
    data = sys.stdin.buffer.read().split()
    n = int(data[0])
    field = data[1].decode()

    packmen = []
    asterisks = []

    for i, c in enumerate(field):
        if c == 'P':
            packmen.append(i)
        elif c == '*':
            asterisks.append(i)

    def check(T):
        j = 0
        n_a = len(asterisks)
        for p in packmen:
            if j >= n_a:
                return True

            left = asterisks[j]

            if left >= p:
                # All remaining asterisks are to the right
                rightmost = p + T
                j = bisect_right(asterisks, rightmost, j)
            else:
                # Some asterisks are to the left
                left_dist = p - left
                if left_dist > T:
                    return False

                opt1 = p + max(0, T - 2 * left_dist)
                opt2 = p + (T - left_dist) // 2
                rightmost = max(opt1, opt2)

                j = bisect_right(asterisks, rightmost, j)

        return j >= n_a

    lo, hi = 0, 2 * 10**5
    while lo < hi:
        mid = (lo + hi) // 2
        if check(mid):
            hi = mid
        else:
            lo = mid + 1

    print(lo)

solve()

