def count_with_k_ones(x, k):
    if x < 0:
        return 0
    if k == 0:
        return 1

    bits = []
    temp = x
    while temp > 0:
        bits.append(temp & 1)
        temp >>= 1
    bits.reverse()

    if not bits:
        return 1 if k == 0 else 0

    n_bits = len(bits)
    result = 0
    ones_so_far = 0

    for i in range(n_bits):
        if bits[i] == 1:
            remaining_bits = n_bits - i - 1
            ones_needed = k - ones_so_far
            if ones_needed >= 0 and ones_needed <= remaining_bits:
                result += comb(remaining_bits, ones_needed)
            ones_so_far += 1

    if ones_so_far == k:
        result += 1

    return result

def comb(n, k):
    if k > n or k < 0:
        return 0
    if k == 0 or k == n:
        return 1
    k = min(k, n - k)
    result = 1
    for i in range(k):
        result = result * (n - i) // (i + 1)
    return result

def count_in_range(n, k):
    return count_with_k_ones(2 * n, k) - count_with_k_ones(n, k)

