    if n < 10:
        return ones[n]
    elif n < 20:
        return teens[n - 10]
    elif n < 100:
        return tens[n // 10] + ones[n % 10]
    else:  # n < 1000
        return hundreds[n // 100] + number_to_words(n % 100)

