from collections import deque, defaultdict

def bfs_paths(graph, start, end, n):
    """Find shortest path from start to end"""
    if start == end:
        return [[start]]

    queue = deque([(start, [start])])
    visited = {start: 0}
    paths = []
    min_len = float('inf')

    while queue:
        node, path = queue.popleft()

        if len(path) > min_len:
            continue

        for neighbor in graph[node]:
            if neighbor == end:
                new_path = path + [neighbor]
                if len(new_path) <= min_len:
                    min_len = len(new_path)
                    paths.append(new_path)
            elif neighbor not in visited or visited[neighbor] >= len(path):
                visited[neighbor] = len(path)
                queue.append((neighbor, path + [neighbor]))

    return paths if paths else []

def check_conflict(paths, producers, K):
    """Check if given producers with their paths have conflicts"""
    edge_usage = defaultdict(set)

    for prod_id, path in zip(producers, paths):
        for i in range(len(path) - 1):
            edge = (path[i], path[i+1])
            time_mod = (prod_id + i) % K
            if time_mod in edge_usage[edge]:
                return True
            edge_usage[edge].add(time_mod)

    return False

def solve():
    N, K, M = map(int, input().split())

    graph = defaultdict(list)
    for _ in range(M):
        a, b = map(int, input().split())
        graph[a].append(b)

    # Find a path for each producer
    producer_paths = []
    for j in range(1, K + 1):
        if j == N:
            producer_paths.append([[N]])
        else:
            paths = bfs_paths(graph, j, N, N)
            if not paths:
                producer_paths.append([])
            else:
                producer_paths.append([paths[0]])  # Use shortest path

    # Try all subsets from largest to smallest
    for size in range(K, 0, -1):
        from itertools import combinations
        for subset in combinations(range(K), size):
            producers = [i + 1 for i in subset]
            paths = [producer_paths[i][0] if producer_paths[i] else [] for i in subset]

            if all(paths) and not check_conflict(paths, producers, K):
                print(size)
                return

    print(0)

solve()

