import math
from sys import stdin

def read_input():
    n = int(input())
    circles = []
    for _ in range(n):
        x, y, r = map(int, input().split())
        circles.append((x, y, r))
    return n, circles

def contains(c1, c2):
    # Check if c1 contains c2
    x1, y1, r1 = c1
    x2, y2, r2 = c2
    dist_sq = (x1 - x2) ** 2 + (y1 - y2) ** 2
    return dist_sq + r2 * r2 <= r1 * r1 + 1e-9

def build_tree(circles):
    n = len(circles)
    # Find parent of each circle (smallest circle that contains it)
    parent = [-1] * n
    children = [[] for _ in range(n)]

    for i in range(n):
        best_parent = -1
        best_radius = float('inf')
        for j in range(n):
            if i != j and contains(circles[j], circles[i]):
                if circles[j][2] < best_radius:
                    best_radius = circles[j][2]
                    best_parent = j
        parent[i] = best_parent
        if best_parent != -1:
            children[best_parent].append(i)

    return parent, children

def solve():
    n, circles = read_input()

    if n == 0:
        print(0)
        return

    parent, children = build_tree(circles)
    areas = [math.pi * r * r for x, y, r in circles]

    # DP on tree: for each node, compute best spaciousness for subtree
    # dp[i][g1][g2] = max spaciousness where g1 circles in group1, g2 in group2
    # But we need to track parity at each level

    # Better approach: for each subtree, compute contribution based on assignment
    def dfs(node, depth_parity):
        # Returns dict: assignment -> (contribution_group1, contribution_group2)
        if not children[node]:
            # Leaf node
            sign = 1 if depth_parity == 0 else -1
            return {
                0: (0, sign * areas[node]),  # assign to group 2
                1: (sign * areas[node], 0)   # assign to group 1
            }

        # Combine children results
        result = {0: (0, 0), 1: (0, 0)}

        for child in children[node]:
            child_results = dfs(child, 1 - depth_parity)
            new_result = {}
            for mask1, (c1_1, c1_2) in result.items():
                for mask2, (c2_1, c2_2) in child_results.items():
                    new_mask = mask1  # We'll handle this differently
                    new_c1 = c1_1 + c2_1
                    new_c2 = c1_2 + c2_2
                    key = (mask1, mask2)
                    if key not in new_result:
                        new_result[key] = (new_c1, new_c2)

        # This is getting complex, let me use simpler brute force
        return None

    # Brute force: try all 2^n assignments
    max_spaciousness = 0

    for mask in range(1 << n):
        space1 = 0
        space2 = 0

        for i in range(n):
            # Count depth in respective group
            depth1 = 0
            depth2 = 0
            curr = i

            while curr != -1:
                if mask & (1 << curr):
                    depth1 += 1
                else:
                    depth2 += 1
                curr = parent[curr]

            if mask & (1 << i):
                if depth1 % 2 == 1:
                    space1 += areas[i]
                else:
                    space1 -= areas[i]
            else:
                if depth2 % 2 == 1:
                    space2 += areas[i]
                else:
                    space2 -= areas[i]

        max_spaciousness = max(max_spaciousness, space1 + space2)

    print(f"{max_spaciousness:.10f}")

solve()

