def parse_program(tokens):
    """Parse tokens into a structured program"""
    result = []
    i = 0
    while i < len(tokens):
        token = tokens[i]
        if token.startswith('V'):
            result.append(('V', int(token[1:])))
            i += 1
        elif token.startswith('R'):
            n = int(token[1:])
            # Find matching E
            depth = 1
            j = i + 1
            while depth > 0:
                if tokens[j].startswith('R'):
                    depth += 1
                elif tokens[j] == 'E':
                    depth -= 1
                j += 1
            body = parse_program(tokens[i+1:j-1])
            result.append(('R', n, body))
            i = j
        i += 1
    return result

def count_cost(program, var_to_bank, b):
    """Count instructions needed with given variable assignment"""
    bsr = -1  # undefined
    cost = 0

    def process(prog):
        nonlocal bsr, cost
        for item in prog:
            if item[0] == 'V':
                var = item[1]
                bank = var_to_bank[var]
                if bank == 0:
                    cost += 1
                else:
                    if bsr != bank:
                        cost += 1  # set BSR
                        bsr = bank
                    cost += 1  # access
            elif item[0] == 'R':
                n, body = item[1], item[2]
                for _ in range(n):
                    process(body)

    process(program)
    return cost

def solve():
    line1 = input().split()
    b, s = int(line1[0]), int(line1[1])
    tokens = input().split()

    program = parse_program(tokens)

    # Get all variables used
    def get_vars(prog):
        vars_set = set()
        for item in prog:
            if item[0] == 'V':
                vars_set.add(item[1])
            elif item[0] == 'R':
                vars_set.update(get_vars(item[2]))
        return vars_set

    variables = sorted(get_vars(program))
    num_vars = len(variables)

    if num_vars == 0:
        print(0)
        return

    # Try all possible assignments
    min_cost = float('inf')

    # Simple greedy: put most frequent in bank 0
    from itertools import combinations

    bank0_size = min(s, num_vars)

    for bank0_vars in combinations(variables, bank0_size):
        var_to_bank = {}
        bank0_set = set(bank0_vars)
        for v in bank0_vars:
            var_to_bank[v] = 0

        other_vars = [v for v in variables if v not in bank0_set]
        bank_idx = 1
        for v in other_vars:
            var_to_bank[v] = bank_idx
            bank_idx = (bank_idx % b) + 1 if bank_idx < b else 1

        cost = count_cost(program, var_to_bank, b)
        min_cost = min(min_cost, cost)

    print(min_cost)

