        if n * n != n_squared:
            continue

        # Now find m such that ceil(n/m) = k
        # This means (k-1) < n/m <= k
        # So n/k <= m < n/(k-1) if k > 1
        # Or m >= n if k = 1

        if k == 1:
            # ceil(n/m) = 1 means n/m <= 1, so m >= n
            m = n
            return (n, m)
        else:
            # We need (k-1) < n/m <= k
            # So n/k <= m < n/(k-1)
            m_min = (n + k - 1) // k  # This is ceil(n/k)
            m_max = n // (k - 1)

            if m_min <= m_max:
                # Check if ceil(n/m_min) == k
                if (n + m_min - 1) // m_min == k:
                    return (n, m_min)

    return None

