def can_eat_all(packmen, asterisks, time):
    if not asterisks:
        return True

    pack_idx = 0
    ast_idx = 0

    while ast_idx < len(asterisks) and pack_idx < len(packmen):
        p = packmen[pack_idx]

        # If this packman can't reach the current asterisk, try next packman
        if p + time < asterisks[ast_idx]:
            pack_idx += 1
            continue

        # This packman will handle asterisks starting from ast_idx
        # Find the rightmost asterisk this packman can eat

        # Strategy 1: Go left first, then right
        # Can go left to max(p - time, asterisks[ast_idx]) and right to p + time
        left_bound = asterisks[ast_idx]
        if left_bound <= p:
            # Going left by (p - left_bound), then can go right by (time - 2*(p - left_bound))
            right_reach1 = p + max(0, time - 2 * (p - left_bound))
        else:
            right_reach1 = -1

        # Strategy 2: Go right first, then left
        # Start from p, go right as far as possible, then come back left
        # If we go right by r, we need r + 2*(p - left_bound) <= time
        # So r <= time - 2*(p - left_bound)
        if left_bound <= p:
            right_reach2 = p + time
        else:
            right_reach2 = -1

        right_reach = max(right_reach1, right_reach2)

        # Find rightmost asterisk within reach
        while ast_idx < len(asterisks) and asterisks[ast_idx] <= right_reach:
            ast_idx += 1

        pack_idx += 1

    return ast_idx >= len(asterisks)

