def count_with_k_ones(x, k):
    """Count numbers from 1 to x with exactly k ones in binary"""
    if x <= 0:
        return 0

    # Use memoization for digit DP
    memo = {}

    def dp(pos, ones, tight):
        # pos: current bit position (from high to low)
        # ones: count of ones so far
        # tight: whether we're still bounded by x

        if ones > k:
            return 0
        if pos < 0:
            return 1 if ones == k else 0

        if (pos, ones, tight) in memo:
            return memo[(pos, ones, tight)]

        limit = (x >> pos) & 1 if tight else 1
        result = 0

        for digit in range(limit + 1):
            new_tight = tight and (digit == limit)
            result += dp(pos - 1, ones + digit, new_tight)

        memo[(pos, ones, tight)] = result
        return result

    # Find the highest bit position
    if x == 0:
        return 0

    highest_bit = x.bit_length() - 1
    return dp(highest_bit, 0, True)

