def forward(pos, n):
    for i in range(1, n+1):
        if i % 2 == 1:  # odd move: swap 0 and 1
            if pos == 0:
                pos = 1
            elif pos == 1:
                pos = 0
        else:  # even move: swap 1 and 2
            if pos == 1:
                pos = 2
            elif pos == 2:
                pos = 1
    return pos

