def solve(s):
    max_pile = 1  # At minimum, no folds gives us piles of size 1

    def simulate_folds(text, folds):
        # folds is a list of positions where we fold
        # Returns a 2D grid (list of lists)
        if not folds:
            return [[c] for c in text]

        folds = sorted(folds)
        grid = [[c] for c in text]

        # Apply folds from right to left to maintain positions
        for fold_pos in reversed(folds):
            new_grid = [[] for _ in range(len(grid))]

            # Left part stays
            for i in range(fold_pos):
                new_grid[i] = grid[i][:]

            # Right part flips and goes on top
            right_part = grid[fold_pos:]
            for i, row in enumerate(right_part):
                col_idx = fold_pos - 1 - i
                if col_idx >= 0:
                    new_grid[col_idx].extend(row)
                else:
                    # This shouldn't happen with valid folds
                    pass

            grid = new_grid[:fold_pos]

        return grid

    def get_max_pile(grid):
        if not grid:
            return 0
        max_h = 0
        for col in grid:
            if not col:
                continue
            # Check for valid pile (all same char from bottom)
            char = col[0]
            height = 0
            for c in col:
                if c == char:
                    height += 1
                else:
                    break
            max_h = max(max_h, height)
        return max_h

    def try_folds(pos, current_folds):
        nonlocal max_pile

        if pos >= len(s):
            grid = simulate_folds(s, current_folds)
            pile = get_max_pile(grid)
            max_pile = max(max_pile, pile)
            return

        # Try not folding at this position
        try_folds(pos + 1, current_folds)

        # Try folding at this position
        if pos < len(s) - 1:
            try_folds(pos + 1, current_folds + [pos])

    try_folds(0, [])
    return max_pile

