def solve(a, b, m):
    if a == b:
        return [a]

    from collections import deque

    # BFS: state is (current_sum, sequence)
    queue = deque([(a, [a])])
    visited = {a}

    while queue:
        current_sum, sequence = queue.popleft()

        if len(sequence) > 50:
            continue

        # Try all possible next values
        min_next = current_sum + 1
        max_next = current_sum + m

        if b >= min_next and b <= max_next:
            return sequence + [b]

        # Try to add intermediate values
        # Greedy: try values that help us progress toward b
        for r in range(1, m + 1):
            next_val = current_sum + r
            new_sum = current_sum + next_val

            if new_sum not in visited and new_sum <= b * 2:  # Pruning
                visited.add(new_sum)
                queue.append((new_sum, sequence + [next_val]))

    return None

