def solve(n, x, y):
    memo = {}

    def dp(num):
        if num == 0:
            return 0
        if num == 1:
            return x
        if num in memo:
            return memo[num]

        # Option 1: Insert one letter from num-1
        result = dp(num - 1) + x

        # Option 2: Copy from num/2 (if num is even)
        if num % 2 == 0:
            result = min(result, dp(num // 2) + y)
        else:
            # If num is odd, we can:
            # - Get num+1 by copying from (num+1)/2, then delete one
            result = min(result, dp((num + 1) // 2) + y + x)

        memo[num] = result
        return result

    return dp(n)

