class DSU:
    def __init__(self, n):
        self.parent = list(range(n))
        self.size = [1] * n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        px, py = self.find(x), self.find(y)
        if px == py:
            return 0
        if self.size[px] < self.size[py]:
            px, py = py, px
        self.parent[py] = px
        pairs = self.size[px] * self.size[py]
        self.size[px] += self.size[py]
        return pairs

def solve():
    n, m = map(int, input().split())

    edges = []
    for _ in range(n - 1):
        u, v, w = map(int, input().split())
        edges.append((w, u - 1, v - 1))  # 0-indexed

    queries = list(map(int, input().split()))

    # Sort edges by weight
    edges.sort()

    # For each weight threshold, calculate cumulative pairs
    # Create a mapping from weight to number of pairs
    weight_to_pairs = {}
    dsu = DSU(n)

    for w, u, v in edges:
        pairs = dsu.union(u, v)
        if w not in weight_to_pairs:
            weight_to_pairs[w] = 0
        weight_to_pairs[w] += pairs

    # Get sorted unique weights
    sorted_weights = sorted(weight_to_pairs.keys())

    # Create cumulative sum
    cumulative = {}
    total = 0
    for w in sorted_weights:
        total += weight_to_pairs[w]
        cumulative[w] = total

    # Answer queries
    results = []
    for q in queries:
        count = 0
        for w in sorted_weights:
            if w <= q:
                count = cumulative[w]
            else:
                break
        results.append(count)

    print(' '.join(map(str, results)))

