        ])
    return triangles

def get_all_points(triangles):
    """Get all unique points from triangles"""
    points = set()
    for tri in triangles:
        for p in tri:
            points.add(p)
    return points

def point_in_triangle(p, tri):
    """Check if point is inside or on triangle"""
    def sign(p1, p2, p3):
        return (p1[0] - p3[0]) * (p2[1] - p3[1]) - (p2[0] - p3[0]) * (p1[1] - p3[1])

    d1 = sign(p, tri[0], tri[1])
    d2 = sign(p, tri[1], tri[2])
    d3 = sign(p, tri[2], tri[0])

    has_neg = (d1 < 0) or (d2 < 0) or (d3 < 0)
    has_pos = (d1 > 0) or (d2 > 0) or (d3 > 0)

    return not (has_neg and has_pos)

def point_in_triangles(p, triangles):
    """Check if point is in any of the triangles"""
    for tri in triangles:
        if point_in_triangle(p, tri):
            return True
    return False

