import heapq
from collections import defaultdict

def dijkstra(start, graph, n):
    dist = [float('inf')] * (n + 1)
    dist[start] = 0
    pq = [(0, start)]

    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        for v, cost in graph[u]:
            if dist[u] + cost < dist[v]:
                dist[v] = dist[u] + cost
                heapq.heappush(pq, (dist[v], v))

    return dist

def solve():
    n, m = map(int, input().split())

    graph = defaultdict(list)

    for _ in range(m):
        a, b, t = map(int, input().split())
        graph[a].append((b, t))
        graph[b].append((a, t))

    dragon_balls = list(map(int, input().split()))

    # Get unique dragon ball locations
    locations = list(set(dragon_balls))

    # If we can't reach all locations, return -1
    # First check if city 1 is reachable from itself (it always is)

    # Compute shortest paths from city 1 and from each dragon ball location
    dist_from = {}
    dist_from[1] = dijkstra(1, graph, n)

    for loc in locations:
        dist_from[loc] = dijkstra(loc, graph, n)

    # Check if all dragon ball locations are reachable from city 1
    for loc in locations:
        if dist_from[1][loc] == float('inf'):
            print(-1)
            return

    # Now solve TSP with bitmask DP
    # State: dp[mask][i] = minimum cost to visit all dragon balls in mask, ending at location i
    num_locations = len(locations)
    INF = float('inf')

    # dp[mask][i] = min cost to collect dragon balls in mask, currently at locations[i]
    dp = [[INF] * num_locations for _ in range(1 << num_locations)]

    # Find index of city 1 in locations (or start from there)
    start_idx = -1
    for i, loc in enumerate(locations):
        if loc == 1:
            start_idx = i
            break

    if start_idx == -1:
        # City 1 is not a dragon ball location, start from city 1
        # We need to reach the first dragon ball
        for i, loc in enumerate(locations):
            cost = dist_from[1][loc]
            if cost != INF:
                dp[1 << i][i] = cost
    else:
        # City 1 has a dragon ball
        dp[1 << start_idx][start_idx] = 0

    # Fill DP table
    for mask in range(1 << num_locations):
        for i in range(num_locations):
            if dp[mask][i] == INF:
                continue
            if not (mask & (1 << i)):
                continue

            # Try to go to location j
            for j in range(num_locations):
                if mask & (1 << j):
                    continue

                new_mask = mask | (1 << j)
                cost = dp[mask][i] + dist_from[locations[i]][locations[j]]
                dp[new_mask][j] = min(dp[new_mask][j], cost)

    # Find minimum cost to visit all dragon balls
    full_mask = (1 << num_locations) - 1
    result = min(dp[full_mask])

    if result == INF:
        print(-1)
    else:
        print(result)

