        while i < len(tokens):
            token = tokens[i]
            if token == 'E':
                return counts, sequence, i
            elif token.startswith('R'):
                n = int(token[1:])
                sub_counts, sub_seq, end_i = parse_and_count(tokens, i + 1)
                # Multiply by repetition count
                for var in sub_counts:
                    counts[var] = counts.get(var, 0) + sub_counts[var] * n
                sequence.append((n, sub_seq))
                i = end_i + 1
            elif token.startswith('V'):
                var = int(token[1:])
                counts[var] = counts.get(var, 0) + 1
                sequence.append(var)
                i += 1
            else:
                i += 1
        return counts, sequence, len(tokens)

    counts, sequence, _ = parse_and_count(tokens)

    # Sort variables by frequency (descending)
    sorted_vars = sorted(counts.keys(), key=lambda x: -counts[x])

    # Assign variables to banks
    var_to_bank = {}
    for idx, var in enumerate(sorted_vars):
        var_to_bank[var] = idx // s

    # Simulate execution and count cost
    def simulate(seq, var_to_bank):
        cost = 0
        current_bank = None

        def process(s):
            nonlocal cost, current_bank
            for item in s:
                if isinstance(item, int):  # Variable reference
                    var = item
                    bank = var_to_bank[var]
                    if bank == 0:
                        cost += 1
                    else:
                        if current_bank != bank:
                            cost += 1  # BSR setup
                            current_bank = bank
                        cost += 1  # Variable access
                elif isinstance(item, tuple):  # Repetition
                    n, sub_seq = item
                    for _ in range(n):
                        process(sub_seq)

        process(seq)
        return cost

    result = simulate(sequence, var_to_bank)
    print(result)

