from collections import deque, defaultdict

def bfs_shortest_path(n, edges, coloring):
    """Find shortest path from 1 to n given a coloring"""
    # Build adjacency list based on coloring
    graph = defaultdict(list)
    for u, v, t in edges:
        if coloring[u-1] == t:  # Can use this edge if it matches source city color
            graph[u].append(v)

    queue = deque([(1, 0)])
    visited = {1}

    while queue:
        node, dist = queue.popleft()
        if node == n:
            return dist

        for next_node in graph[node]:
            if next_node not in visited:
                visited.add(next_node)
                queue.append((next_node, dist + 1))

    return -1

