import math

def solve(x):
    if x == 0:
        return (1, 1)

    # Try different values of k = ceil(n/m)
    # We need n^2 - k^2 = x
    # So n^2 = x + k^2

    for k in range(1, int(math.sqrt(x)) + 2):
        n_squared = x + k * k
        n = int(math.sqrt(n_squared))

        # Check if n is a perfect square root
        if n * n == n_squared:
            # Now find m such that ceil(n/m) = k
            # ceil(n/m) = k means (n-1)//m < k <= n//m
            # Which means n/k <= m < n/(k-1) if k > 1
            # Or m >= n/k if k = 1

            if k == 1:
                m = n
            else:
                # We need ceil(n/m) = k
                # This means (n + m - 1) // m = k
                # So n + m - 1 >= k*m and n + m - 1 < k*m + m
                # n - 1 >= (k-1)*m and n - 1 < k*m - 1
                # (n-1)/(k-1) >= m and n/k <= m

                m = (n + k - 1) // k

                # Verify
                if math.ceil(n / m) == k and n >= m:
                    return (n, m)

                # Try m = n // k
                m = n // k
                if m > 0 and math.ceil(n / m) == k and n >= m:
                    return (n, m)

    return None

