def f(x, k):
    """Returns the count of numbers in [1, x] with exactly k set bits."""
    if x < 0 or k < 0:
        return 0
    s = bin(x)[2:]
    n = len(s)
    ones_so_far = 0
    ans = 0
    for i in range(n):
        if s[i] == "1":
            remaining_positions = n - 1 - i
            needed_ones = k - ones_so_far
            if 0 <= needed_ones <= remaining_positions:
                ans += math.comb(remaining_positions, needed_ones)
            ones_so_far += 1
    if ones_so_far == k:
        ans += 1
    return ans


