    for i in range(1, n + 1):
        best_a[i] = a[i-1]
        for j in range(1, i):
            best_a[i] = max(best_a[i], best_a[j] + best_a[i-j])

    # Compress string into blocks of (char, length)
    blocks = []
    for char in s:
        if not blocks or blocks[-1][0] != char:
            blocks.append([char, 1])
        else:
            blocks[-1][1] += 1

    m = len(blocks)

    @lru_cache(None)
    def dp(i, j, k):
        if i > j:
            return 0
        if i == j:
            return best_a[blocks[i][1] + k]

        # Option 1: Erase block j and the k extra characters
        res = best_a[blocks[j][1] + k] + dp(i, j-1, 0)

        # Option 2: Merge block j with some block p
        # Since blocks strictly alternate, blocks at j-2, j-4... have the same character as j
        len_j = blocks[j][1]
        for p in range(j - 2, i - 1, -2):
            val = dp(i, p, k + len_j) + dp(p+1, j-1, 0)
            if val > res:
                res = val

        return res

    print(dp(0, m-1, 0))

