    for x in A:
        if x != -1:
            in_A[x] = True

    S = []
    for i in range(1, n + 1):
        if A[i-1] == -1:
            S.append(i)

    m = 0
    for i in S:
        if not in_A[i]:
            m += 1

    k = len(S)

    fact = [1] * (n + 1)
    inv = [1] * (n + 1)
    for i in range(1, n + 1):
        fact[i] = (fact[i-1] * i) % MOD

    inv[n] = pow(fact[n], MOD - 2, MOD)
    for i in range(n - 1, -1, -1):
        inv[i] = (inv[i+1] * (i + 1)) % MOD

    def nCr(n, r):
        if r < 0 or r > n:
            return 0
        return fact[n] * inv[r] % MOD * inv[n-r] % MOD

    ans = 0
    for j in range(m + 1):
        term = nCr(m, j) * fact[k - j] % MOD
        if j % 2 == 1:
            ans = (ans - term + MOD) % MOD
        else:
            ans = (ans + term) % MOD

    print(ans)

