import heapq

def dijkstra(start, T, adj, n, is_target, INF):
    d = [INF] * (n + 1)
    d[start] = 0
    pq = [(0, start)]

    targets_left = len(T)
    visited_targets = [False] * (n + 1)
    dist_from_start = {}

    heappop = heapq.heappop
    heappush = heapq.heappush

    while pq and targets_left > 0:
        dist_u, u = heappop(pq)
        if dist_u > d[u]:
            continue
        if is_target[u] and not visited_targets[u]:
            visited_targets[u] = True
            targets_left -= 1
            dist_from_start[u] = dist_u

        for v, w in adj[u]:
            if d[v] > dist_u + w:
                d[v] = dist_u + w
                heappush(pq, (d[v], v))
    return dist_from_start

