def solve():
    # Read m and k from standard input
    line = sys.stdin.readline()
    if not line:
        return
    m, k = map(int, line.split())

    # Precompute combinations table C(n, k)
    # Max n is around 64 since 2 * 10^18 < 2^61
    combinations = [[0] * 70 for _ in range(70)]
    for i in range(70):
        combinations[i][0] = 1
        for j in range(1, i + 1):
            combinations[i][j] = combinations[i-1][j-1] + combinations[i-1][j]

    # Function to count numbers in range [1, x] with exactly k ones in binary representation
    def count_with_k_ones(x, k):
        if k < 0:
            return 0
        res = 0
        ones_count = 0
        # Iterate through bits from most significant to least significant
        for i in range(63, -1, -1):
            if (x >> i) & 1:
                # If we set this bit to 0, we can choose the remaining ones from the lower bits
                remaining_k = k - ones_count
                if 0 <= remaining_k <= i:
                    res += combinations[i][remaining_k]
                ones_count += 1
        # Check if the number x itself has exactly k ones
        if ones_count == k:
            res += 1
        return res

    # Function g(n) = count of numbers in [n+1, 2n] with exactly k ones
    def g(n):
        return count_with_k_ones(2 * n, k) - count_with_k_ones(n, k)

    # Binary search for n in the range [1, 10^18]
    # g(n) is non-decreasing because g(n+1) - g(n) = (popcount(2n+1) == k)
    low = 1
    high = 10**18
    ans = -1
    while low <= high:
        mid = (low + high) // 2
        val = g(mid)
        if val == m:
            ans = mid
            break
        elif val < m:
            low = mid + 1
        else:
            high = mid - 1

    # Output the result
    if ans != -1:
        print(ans)

