def matches(pattern, filename):
    n = len(pattern)
    m = len(filename)
    # dp[i][j] will be True if pattern[i:] matches filename[j:]
    dp = [[False for _ in range(m + 1)] for _ in range(n + 1)]
    dp[n][m] = True

    # Fill the last column (filename is exhausted)
    # If filename is exhausted, pattern must be all '*' to match
    for i in range(n - 1, -1, -1):
        if pattern[i] == '*':
            dp[i][m] = dp[i+1][m]
        else:
            dp[i][m] = False

    # Fill the rest of the table
    for i in range(n - 1, -1, -1):
        for j in range(m - 1, -1, -1):
            if pattern[i] == '*':
                # '*' can match zero characters (dp[i+1][j])
                # or one or more characters (dp[i][j+1])
                dp[i][j] = dp[i+1][j] or dp[i][j+1]
            elif pattern[i] == filename[j]:
                # Characters must match
                dp[i][j] = dp[i+1][j+1]
            else:
                # Characters do not match
                dp[i][j] = False
    return dp[0][0]

