def matches(pattern: str, s: str) -> bool:
    m, n = len(pattern), len(s)
    dp = [False] * (n + 1)
    dp[0] = True
    for i in range(1, m + 1):
        ch = pattern[i - 1]
        ndp = [False] * (n + 1)
        if ch == '*':
            # '*' matches zero or more characters
            ndp[0] = dp[0]
            for j in range(1, n + 1):
                ndp[j] = dp[j] or ndp[j - 1]
        else:
            for j in range(1, n + 1):
                if dp[j - 1] and ch == s[j - 1]:
                    ndp[j] = True
        dp = ndp
    return dp[n]

