MOD = 10**9 + 7

def main():
    data = sys.stdin.buffer.read().split()
    n = int(data[0])
    a = list(map(int, data[1:]))

    used = [False] * (n + 1)
    missing = []
    unknown_pos = []
    for i, v in enumerate(a, 1):
        if v == -1:
            unknown_pos.append(i)
        else:
            used[v] = True

    for v in range(1, n + 1):
        if not used[v]:
            missing.append(v)

    m = len(unknown_pos)

    # Count positions among unknown where value equals its own index is missing (dangerous for fixed points)
    s = 0
    is_missing = [False] * (n + 1)
    for v in missing:
        is_missing[v] = True
    for pos in unknown_pos:
        if is_missing[pos]:
            s += 1

    # Precompute factorials and inverse factorials up to m
    fact = [1] * (m + 1)
    for i in range(1, m + 1):
        fact[i] = fact[i - 1] * i % MOD

    invfact = [1] * (m + 1)
    invfact[m] = pow(fact[m], MOD - 2, MOD)
    for i in range(m, 0, -1):
        invfact[i - 1] = invfact[i] * i % MOD

    # Derangements up to s
    der = [0] * (s + 1)
    if s >= 0:
        der[0] = 1
    if s >= 1:
        der[1] = 0
    for i in range(2, s + 1):
        der[i] = (i - 1) * (der[i - 1] + der[i - 2]) % MOD

    # Inclusion-exclusion:
    # ways = sum_{k=0..s} (-1)^k * C(s,k) * (m-k)!
    # = sum_{k=0..s} (-1)^k * C(s,k) * fact[m-k]
    ans = 0
    for k in range(0, s + 1):
        comb = fact[s] * invfact[k] % MOD * invfact[s - k] % MOD
        term = comb * fact[m - k] % MOD
        if k & 1:
            ans = (ans - term) % MOD
        else:
            ans = (ans + term) % MOD

    # Equivalent check via derangements formula:
    # ans2 = sum_{t=0..s} C(s,t) * der[t] * fact[m-t] / ??? (not needed)

    sys.stdout.write(str(ans % MOD))

