def main():
    board = [list(sys.stdin.readline().strip()) for _ in range(8)]

    # For each pawn, compute the earliest move count to reach the goal row,
    # assuming it can move only forward into empty squares (which may change
    # due to other moves, but optimal play reduces to earliest achievable time).
    # In this game (no captures), the winner is determined by comparing:
    #  - A's minimal required moves for some white pawn to reach row 1
    #  - B's minimal required moves for some black pawn to reach row 8
    # with A moving first (so A wins ties).
    INF = 10**9
    bestA = INF
    bestB = INF

    # White pawns move up (decreasing row index)
    for r in range(8):
        for c in range(8):
            if board[r][c] == 'W':
                steps = 0
                rr = r
                ok = True
                while rr > 0:
                    if board[rr - 1][c] != '.':
                        ok = False
                        break
                    rr -= 1
                    steps += 1
                if ok:
                    bestA = min(bestA, steps)

    # Black pawns move down (increasing row index)
    for r in range(8):
        for c in range(8):
            if board[r][c] == 'B':
                steps = 0
                rr = r
                ok = True
                while rr < 7:
                    if board[rr + 1][c] != '.':
                        ok = False
                        break
                    rr += 1
                    steps += 1
                if ok:
                    bestB = min(bestB, steps)

    # A moves first; if both can win in same number of moves, A wins.
    if bestA <= bestB:
        sys.stdout.write("A")
    else:
        sys.stdout.write("B")

