def is_valid(password: str, message: str) -> bool:
    P = len(password)
    sets = []
    cur = set()
    for i in range(P - 1, -1, -1):
        cur.add(password[i])
        sets.append(cur.copy())
    sets.reverse()  # sets[i] = {password[i], ..., password[P-1]}

    pos = 0
    for i in range(P):
        target_set = sets[i]
        found = False
        while pos < len(message):
            ch = message[pos]
            pos += 1
            if ch in target_set:
                found = True
                if ch != password[i]:
                    return False
                break
        if not found:
            return False
    return True

