def feasible(a, n, k, mid):
    pref = 0.0
    min_pref = 0.0
    pref_k = 0.0
    for i in range(n):
        pref += a[i] - mid
        if i >= k - 1:
            if pref - min_pref >= 0:
                return True
            pref_k += a[i - (k - 1)] - mid
            if pref_k < min_pref:
                min_pref = pref_k
    return False

