import sys

INF = 10**30

class Node:
    __slots__ = ("kind", "var", "rep", "child")
    def __init__(self, kind, var=None, rep=None, child=None):
        self.kind = kind  # 'V' or 'R'
        self.var = var
        self.rep = rep
        self.child = child

def parse_program(tokens):
    idx = 0

    def parse_seq():
        nonlocal idx
        seq = []
        while idx < len(tokens) and tokens[idx] != 'E':
            tok = tokens[idx]
            if tok[0] == 'V':
                seq.append(Node('V', var=int(tok[1:]) - 1))
                idx += 1
            elif tok[0] == 'R':
                n = int(tok[1:])
                idx += 1
                body = parse_seq()
                if idx >= len(tokens) or tokens[idx] != 'E':
                    raise ValueError("Missing E")
                idx += 1
                seq.append(Node('R', rep=n, child=body))
            else:
                raise ValueError("Bad token: " + tok)
        return seq

    prog = parse_seq()
    if idx != len(tokens):
        raise ValueError("Extra tokens")
    return prog

def solve_for_mapping(prog, var_bank, b, s):
    # DP for a sequence returns matrix dp[start_state][end_state]
    # states: 0..b-1 => BSR defined with that bank, b => undefined
    U = b

    def seq_dp(seq):
        # identity matrix: cost 0 from x to x
        size = b + 1
        mat = [[INF]*size for _ in range(size)]
        for i in range(size):
            mat[i][i] = 0

        def matmul(A, B):
            size = b + 1
            C = [[INF]*size for _ in range(size)]
            # min-plus matrix multiplication
            for i in range(size):
                Ai = A[i]
                Ci = C[i]
                for k in range(size):
                    aik = Ai[k]
                    if aik >= INF: 
                        continue
                    Bk = B[k]
                    for j in range(size):
                        v = aik + Bk[j]
                        if v < Ci[j]:
                            Ci[j] = v
            return C

        def var_mat(v):
            size = b + 1
            M = [[INF]*size for _ in range(size)]
            bank = var_bank[v]
            if bank == 0:
                # can use a=0 always; BSR unchanged
                for st in range(size):
                    M[st][st] = 1
            else:
                # must use a=1; ensure BSR=bank (may need set)
                for st in range(size):
                    # if st==bank => no set, else set (including undefined)
                    cost = 1 + (0 if st == bank else 1)
                    M[st][bank] = cost
            return M

        def minplus_mat_add_const(A, c):
            size = b + 1
            C = [[INF]*size for _ in range(size)]
            for i in range(size):
                for j in range(size):
                    if A[i][j] < INF:
                        C[i][j] = A[i][j] + c
            return C

        def minplus_mat_min(A, B):
            size = b + 1
            C = [[INF]*size for _ in range(size)]
            for i in range(size):
                for j in range(size):
                    C[i][j] = A[i][j] if A[i][j] < B[i][j] else B[i][j]
            return C

        def minplus_mat_pow(M, n):
            size = b + 1
            # fast exponentiation under min-plus
            # identity
            R = [[INF]*size for _ in range(size)]
            for i in range(size):
                R[i][i] = 0
            base = M
            while n > 0:
                if n & 1:
                    R = matmul(R, base)
                n >>= 1
                if n:
                    base = matmul(base, base)
            return R

        # compute matrix for each node and multiply in sequence
        for node in seq:
            if node.kind == 'V':
                M = var_mat(node.var)
            else:
                bodyM = seq_dp(node.child)
                M = minplus_mat_pow(bodyM, node.rep)
            mat = matmul(mat, M)
        return mat

    fullM = seq_dp(prog)
    # initial state undefined
    ans = min(fullM[U][j] for j in range(b+1))
    return ans

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    b = int(data[0]); s = int(data[1])
    tokens = data[2:]
    prog = parse_program(tokens)

    V = min(b*s, 13)

    # Enumerate all mappings var->bank, each bank capacity s, bank count b
    var_bank = [-1]*V
    cap = [s]*b
    best = INF

    # Pre-calc list of vars used? But mapping still depends; only vars 0..V-1 exist.
    # If some vars unused, mapping irrelevant; still can assign anywhere.
    # We'll compute usage to prune by only assigning used vars; unused vars can be arbitrary.
    used = [0]*V

    def mark_used(seq):
        for node in seq:
            if node.kind == 'V':
                if 0 <= node.var < V:
                    used[node.var] = 1
            else:
                mark_used(node.child)
    mark_used(prog)
    vars_to_assign = [i for i in range(V) if used[i]]
    if not vars_to_assign:
        print(0)
        return

    # Backtracking over used vars only.
    # For banks beyond b, cap is 0. But b given.
    sys.setrecursionlimit(10000)

    def dfs(t):
        nonlocal best
        if t == len(vars_to_assign):
            # assign remaining unused vars arbitrarily without affecting
            # Ensure unassigned var_bank entries set to 0 to avoid errors
            for i in range(V):
                if var_bank[i] == -1:
                    var_bank[i] = 0
            cost = solve_for_mapping(prog, var_bank, b, s)
            if cost < best:
                best = cost
            # reset unused to -1
            for i in range(V):
                if used[i] == 0:
                    var_bank[i] = -1
            return
        v = vars_to_assign[t]
        # try each bank with capacity
        for bank in range(b):
            if cap[bank] <= 0:
                continue
            cap[bank] -= 1
            var_bank[v] = bank
            dfs(t+1)
            var_bank[v] = -1
            cap[bank] += 1

    dfs(0)
    print(best)

