import sys

def can(T, stars, packs):
    j = 0
    m = len(stars)
    for p in packs:
        if j >= m:
            return True
        if stars[j] < p:
            L = stars[j]
            if p - L > T:
                continue  # this pack can't even reach leftmost remaining star
            d = p - L
            # after covering left to L, max reachable to the right within T:
            # option1: go left first then right: remaining time = T - 2d
            # option2: go right first then left: need d to come back, so right reach = p + (T - d)//2
            right_reach = max(p + (T - 2 * d), p + (T - d) // 2)
            while j < m and stars[j] <= right_reach:
                j += 1
        else:
            # leftmost remaining star is to the right of (or at) p
            right_reach = p + T
            while j < m and stars[j] <= right_reach:
                j += 1
    return j >= m

