import sys
from collections import deque

def hopcroft_karp(adj, n_left, n_right):
    INF = 10**9
    pair_u = [-1] * n_left
    pair_v = [-1] * n_right
    dist = [0] * n_left

    def bfs():
        q = deque()
        for u in range(n_left):
            if pair_u[u] == -1:
                dist[u] = 0
                q.append(u)
            else:
                dist[u] = INF
        d_augment = INF
        while q:
            u = q.popleft()
            if dist[u] >= d_augment:
                continue
            for v in adj[u]:
                u2 = pair_v[v]
                if u2 == -1:
                    d_augment = dist[u] + 1
                else:
                    if dist[u2] == INF:
                        dist[u2] = dist[u] + 1
                        q.append(u2)
        return d_augment != INF

    def dfs(u):
        for v in adj[u]:
            u2 = pair_v[v]
            if u2 == -1 or (dist[u2] == dist[u] + 1 and dfs(u2)):
                pair_u[u] = v
                pair_v[v] = u
                return True
        dist[u] = INF
        return False

    matching = 0
    while bfs():
        for u in range(n_left):
            if pair_u[u] == -1 and dfs(u):
                matching += 1
    return matching

