import sys

CAP = 10**18 + 5

def build_combinations(max_n=64):
    C = [[0] * (max_n + 1) for _ in range(max_n + 1)]
    for n in range(max_n + 1):
        C[n][0] = 1
        C[n][n] = 1
        for r in range(1, n):
            v = C[n - 1][r - 1] + C[n - 1][r]
            if v > CAP:
                v = CAP
            C[n][r] = v
    return C

C = build_combinations(64)

def count_popcount_k_upto(x, k):
    if x < 0:
        return 0
    # count numbers in [0..x] with exactly k ones
    bits = x.bit_length()
    ans = 0
    ones = 0
    for i in range(bits - 1, -1, -1):
        if (x >> i) & 1:
            # set this bit to 0 and choose remaining ones from i lower bits
            need = k - ones
            if 0 <= need <= i:
                ans += C[i][need]
                if ans >= CAP:
                    return CAP
            ones += 1
            if ones > k:
                return ans
    if ones == k:
        ans += 1
        if ans >= CAP:
            return CAP
    return ans

def count_in_open_closed(n, k):
    # count numbers in (n, 2n] with popcount==k
    return count_popcount_k_upto(2 * n, k) - count_popcount_k_upto(n, k)

