        # n=1e18 is safe given constraints existence; try to locate with search.
        # If k>64, none; but k<=64.
        hi = 10**18
        lo = 1
        ans = None
        while lo <= hi:
            mid = (lo + hi) // 2
            val = count_in_open_closed(mid, k)
            if val >= m:
                ans = mid
                hi = mid - 1
            else:
                lo = mid + 1
        if ans is None:
            ans = 1
        # adjust a bit to find exact zero if possible
        for t in range(max(1, ans - 200), min(10**18, ans + 200) + 1):
            if count_in_open_closed(t, k) == 0:
                print(t)
                return
        print(1)
        return

    lo, hi = 1, 10**18
    best = None
    while lo <= hi:
        mid = (lo + hi) // 2
        val = count_in_open_closed(mid, k)
        if val >= m:
            best = mid
            hi = mid - 1
        else:
