MOD = 10**9 + 7

def modinv(a):
    return pow(a, MOD - 2, MOD)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    x, y = map(int, data)
    nmax = x + y

    # Fibonacci up to max(x, y)
    m = max(x, y)
    fib = [0] * (m + 1)
    if m >= 1:
        fib[1] = 1
    for i in range(2, m + 1):
        fib[i] = (fib[i - 1] + fib[i - 2]) % MOD

    # factorials for binomials up to x+y
    fact = [1] * (nmax + 1)
    for i in range(1, nmax + 1):
        fact[i] = (fact[i - 1] * i) % MOD
    invfact = [1] * (nmax + 1)
    invfact[nmax] = modinv(fact[nmax])
    for i in range(nmax, 0, -1):
        invfact[i - 1] = (invfact[i] * i) % MOD

    def comb(n, r):
        if r < 0 or r > n:
            return 0
        return (fact[n] * invfact[r] % MOD) * invfact[n - r] % MOD

    # F[x, y] = sum_{k=1..x} Fib(k) * C(x+y-k-1, y-1) + sum_{l=1..y} Fib(l) * C(x+y-l-1, x-1)
    ans = 0
    r1 = y - 1
    for k in range(1, x + 1):
        ans = (ans + fib[k] * comb(x + y - k - 1, r1)) % MOD

    r2 = x - 1
    for l in range(1, y + 1):
        ans = (ans + fib[l] * comb(x + y - l - 1, r2)) % MOD

    sys.stdout.write(str(ans))

