MOD = 1_000_000_007

def modinv(a):
    return pow(a, MOD - 2, MOD)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])
    arr = list(map(int, data[1:]))

    used_vals = [False] * (n + 1)
    is_unknown_pos = [False] * (n + 1)

    m = 0  # number of -1 positions
    for i in range(1, n + 1):
        x = arr[i - 1]
        if x == -1:
            is_unknown_pos[i] = True
            m += 1
        else:
            used_vals[x] = True

    # Vrem = values not used in given positives
    s = 0
    for i in range(1, n + 1):
        if is_unknown_pos[i] and not used_vals[i]:
            s += 1

    # Precompute factorials and inverse factorials up to n
    fact = [1] * (n + 1)
    for i in range(1, n + 1):
        fact[i] = fact[i - 1] * i % MOD

    invfact = [1] * (n + 1)
    invfact[n] = modinv(fact[n])
    for i in range(n, 0, -1):
        invfact[i - 1] = invfact[i] * i % MOD

    def C(n_, r_):
        if r_ < 0 or r_ > n_:
            return 0
        return fact[n_] * invfact[r_] % MOD * invfact[n_ - r_] % MOD

    # Inclusion-exclusion:
    # ans = sum_{t=0..s} (-1)^t * C(s,t) * (m-t)!
    ans = 0
    for t in range(s + 1):
        ways = C(s, t) * fact[m - t] % MOD
        if t % 2 == 0:
            ans = (ans + ways) % MOD
        else:
            ans = (ans - ways) % MOD

    print(ans % MOD)

