def solve():
    it = iter(sys.stdin.read().strip().split())
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it)); m = int(next(it))
        a = [int(next(it)) for _ in range(n)]
        p = [int(next(it)) for _ in range(m)]
        allowed = set(x - 1 for x in p)  # 0-based positions i where swap i and i+1 if i in allowed

        parent = list(range(n))
        rank = [0] * n

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(x, y):
            x = find(x); y = find(y)
            if x == y:
                return
            if rank[x] < rank[y]:
                parent[x] = y
            elif rank[x] > rank[y]:
                parent[y] = x
            else:
                parent[y] = x
                rank[x] += 1

        for i in range(n - 1):
            if i in allowed:
                union(i, i + 1)

        comps = {}
        for i in range(n):
            r = find(i)
            comps.setdefault(r, []).append(i)

        b = sorted(a)
        ok = True
        for idxs in comps.values():
            cur = sorted(a[i] for i in idxs)
            tgt = sorted(b[i] for i in idxs)
            if cur != tgt:
                ok = False
                break

        out_lines.append("YES" if ok else "NO")

    sys.stdout.write("\n".join(out_lines))

