def ceil_div(a, b):
    return -(-a // b)

def feasible(x, y, m, sigma):
    if x < 1 or y < 1:
        return False
    if x + y > m:
        return False
    if 2 * x + y < sigma:
        return False
    return True

def main():
    data = list(map(int, sys.stdin.read().strip().split()))
    if len(data) != 4:
        return
    a, b, m, sigma = data

    # Candidate x values derived from constraint intersections
    cand_x = set()
    cand_x.add(1)
    cand_x.add(m - 1)

    # From y=1 and 2x+y >= sigma => 2x+1 >= sigma
    cand_x.add(max(1, sigma // 2))  # sigma even => sigma/2 is smallest integer x with inequality

    # From x+y=m and 2x+y=sigma equality: x+m = sigma => x = sigma - m
    cand_x.add(sigma - m)
    cand_x.add(sigma - m + 1)
    cand_x.add(sigma - m - 1)

    # From x=1 and 2x+y=sigma => y=sigma-2
    # (x=1 already included, no need to add here)

    # From where lower bound switches: sigma - 2x = 1 => x = (sigma-1)/2
    # Consider both sides as sigma even => (sigma-1)/2 is .5
    cand_x.add(sigma // 2)
    cand_x.add(sigma // 2 - 1)
    cand_x.add(sigma // 2 + 1)

    # Also add neighbors around candidates for safety
    cand_x2 = set()
    for x in cand_x:
        for dx in range(-3, 4):
            cand_x2.add(x + dx)

    best = None

    for x in cand_x2:
        if x < 1 or x > m - 1:
            continue
        lower = max(1, sigma - 2 * x)
        upper = m - x
        if lower > upper:
            continue

        for y in (lower, upper):
            if feasible(x, y, m, sigma):
                R = a * x + b * y
                if best is None or R > best:
                    best = R

    # Problem guarantees solution exists.
    print(best)

