def edge_key(ax, ay, bx, by):
    if (ax, ay) <= (bx, by):
        return (ax, ay, bx, by)
    else:
        return (bx, by, ax, ay)

def boundary_edges(triangles):
    # triangles: iterable of 6-int tuples
    cnt = {}
    for x1, y1, x2, y2, x3, y3 in triangles:
        e1 = edge_key(x1, y1, x2, y2)
        e2 = edge_key(x2, y2, x3, y3)
        e3 = edge_key(x3, y3, x1, y1)
        cnt[e1] = cnt.get(e1, 0) + 1
        cnt[e2] = cnt.get(e2, 0) + 1
        cnt[e3] = cnt.get(e3, 0) + 1
    # boundary edges are those appearing exactly once
    return {e for e, c in cnt.items() if c == 1}

