import sys, math

def compute_d(e, a, b, gap_len):
    # h(E)=h(E-a)+h(E-b), with h(E<=0)=1
    # g(E)=1/h(E); answer = gap_len * g(e)
    if e <= 0:
        return float(gap_len)

    logh = [0.0] * (e + 1)  # log(h[n]); base h<=0 => 1 => log 1 = 0

    for n in range(1, e + 1):
        if n - a <= 0:
            la = 0.0
        else:
            la = logh[n - a]

        if n - b <= 0:
            lb = 0.0
        else:
            lb = logh[n - b]

        m = la if la >= lb else lb
        if m == float("inf"):
            logh[n] = m
            continue
        d1 = la - m
        d2 = lb - m
        # log(exp(d1)+exp(d2)) + m with exp terms stable
        if d1 < -50:
            # exp(d1) negligible
            logh[n] = m + math.log1p(math.exp(d2 - d1)) if d2 - d1 > 0 else m + math.log1p(0.0)
            # Actually if d1 negligible, exp(d2) may be 1 (if d2==0)
            # simpler:
            if d2 < -50:
                # both negligible (shouldn't happen with m=max)
                logh[n] = m + 0.0
            else:
                logh[n] = m + math.log1p(math.exp(d2))
        elif d2 < -50:
            logh[n] = m + math.log1p(math.exp(d1))
        else:
            logh[n] = m + math.log(math.exp(d1) + math.exp(d2))

    # g = 1/h = exp(-logh)
    g = math.exp(-logh[e])
    return gap_len * g

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    e, es, ef = map(int, data)
    a = es
    b = ef

    # Option 1: Treat initial score as 0 and unknown strength in [0,225] worst-case gap 225.
    d1 = compute_d(e, a, b, 225.0)

    # Option 2: First guarantee scoring at least 25 by attempting w=25 (success guaranteed).
    # That consumes energy a (e_success). Then state corresponds to score=lower endpoint.
    if e - a > 0:
        d2 = compute_d(e - a, a, b, 200.0)  # gap 225-25
    else:
        # Not enough remaining energy for further reduction; worst-case after first guaranteed success is still 200
        d2 = 200.0

    d = d1 if d1 < d2 else d2
    # Print with sufficient precision
    sys.stdout.write(f"{d:.15g}\n")

