import sys
import heapq

def dijkstra(start, adj, n):
    INF = 10**30
    dist = [INF] * (n + 1)
    dist[start] = 0
    h = [(0, start)]
    while h:
        d, u = heapq.heappop(h)
        if d != dist[u]:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd
                heapq.heappush(h, (nd, v))
    return dist

def main():
    sys.setrecursionlimit(1_000_000)
    input_data = sys.stdin.buffer.read().split()
    if not input_data:
        return
    it = iter(input_data)
    n = int(next(it))
    m = int(next(it))

    adj = [[] for _ in range(n + 1)]
    for _ in range(m):
        a = int(next(it)); b = int(next(it)); t = int(next(it))
        adj[a].append((b, t))
        adj[b].append((a, t))

    targets_raw = [int(next(it)) for _ in range(7)]
    targets = sorted(set(targets_raw))
    k = len(targets)
    # Map target city -> bit index [0..k-1]
    target_to_bit = {c: i for i, c in enumerate(targets)}

    start_city = 1
    # Relevant positions: start + unique target cities (some may overlap)
    pos_cities = [start_city]
    pos_index = {start_city: 0}
    for c in targets:
        if c not in pos_index:
            pos_index[c] = len(pos_cities)
            pos_cities.append(c)
    r = len(pos_cities)

    # Run Dijkstra from each relevant position
    dists = [[0] * r for _ in range(r)]
    INF = 10**30
    for i, city in enumerate(pos_cities):
        dist = dijkstra(city, adj, n)
        for j, city2 in enumerate(pos_cities):
            dists[i][j] = dist[city2]

    # If some target is unreachable from start, we can early detect later in DP,
    # but also ensure no INF pair among relevant nodes that we might need.
    # Initialize DP
    full_mask = (1 << k) - 1
    init_mask = 0
    if start_city in target_to_bit:
        init_mask |= 1 << target_to_bit[start_city]

    dp = [[INF] * r for _ in range(1 << k)]
    dp[init_mask][pos_index[start_city]] = 0

    # Precompute which pos indices correspond to each target bit
    target_pos = [-1] * k
    for c, bit in target_to_bit.items():
        target_pos[bit] = pos_index[c]

    for mask in range(1 << k):
        for pos in range(r):
            cur = dp[mask][pos]
            if cur >= INF:
                continue
            if mask == full_mask:
                continue
            # Try to go to any next target
            for bit in range(k):
                if (mask >> bit) & 1:
                    continue
                np = target_pos[bit]
                nd = cur + dists[pos][np]
                if nd < dp[mask | (1 << bit)][np]:
                    dp[mask | (1 << bit)][np] = nd

    ans = min(dp[full_mask])
    if ans >= INF:
        print(-1)
    else:
        print(ans)

