import sys, math

def solve():
    input_data = sys.stdin.buffer.read().split()
    n = int(input_data[0])
    pts = []
    ys = []
    idx = 1
    for _ in range(n):
        x = int(input_data[idx]); y = int(input_data[idx+1]); idx += 2
        pts.append((x, y))
        ys.append(y)

    pos = all(y > 0 for y in ys)
    neg = all(y < 0 for y in ys)
    if not (pos or neg):
        print(-1)
        return

    sgn = 1 if pos else -1  # transform so all y > 0
    arr = []
    for x, y in pts:
        arr.append((float(x), float(sgn * y)))  # y > 0

    def feasible(r: float) -> bool:
        L = -1e100
        R = 1e100
        for x, y in arr:
            t = 2.0 * y * r - y * y
            if t < -1e-12:
                return False
            if t < 0.0:
                t = 0.0
            d = math.sqrt(t)
            li = x - d
            ri = x + d
            if li > L:
                L = li
            if ri < R:
                R = ri
            if L > R + 1e-12:
                return False
        return True

    lo = 0.0
    hi = 1.0
    while not feasible(hi):
        hi *= 2.0
        if hi > 1e18:
            print(-1)
            return

    for _ in range(80):
        mid = (lo + hi) / 2.0
        if feasible(mid):
            hi = mid
        else:
            lo = mid

    print(hi)

