import math

def isqrt(n: int) -> int:
    return math.isqrt(n)

def ceil_sqrt(n: int) -> int:
    r = isqrt(n)
    return r if r * r == n else r + 1

def solve_one(x: int):
    if x == 0:
        return 1, 1

    # Assume m >= 2 and (conjectured/known) maximum ones:
    # ans(n,m) = n^2 - n + m - 1, for 2 <= m <= n
    # => m - 1 = x - (n^2 - n)
    # Need: 1 <= m-1 <= n-1  <=>  n^2 - n + 1 <= x <= n^2 - 1
    # => ceil_sqrt(x+1) <= n <= floor((1 + sqrt(4x-3))/2)

    n_min = ceil_sqrt(x + 1)
    # From x >= n^2 - n + 1  => n^2 - n - (x - 1) <= 0
    # roots: (1 +/- sqrt(1 + 4(x-1))) / 2 = (1 +/- sqrt(4x-3))/2
    disc = 4 * x - 3
    if disc < 0:
        return None
    n_max = (1 + isqrt(disc)) // 2
    if n_min > n_max:
        return None

    # Try candidates near boundaries (usually enough); also avoid too many iterations.
    candidates = set()
    for dn in range(0, 8):
        if n_min + dn <= n_max:
            candidates.add(n_min + dn)
        if n_max - dn >= n_min:
            candidates.add(n_max - dn)

    for n in sorted(candidates):
        m = x - (n * n - n) + 1  # m = x - n^2 + n + 1
        if 2 <= m <= n:
            return n, m
    return None

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    xs = list(map(int, data[1:]))

    out = []
    for i in range(t):
        x = xs[i]
        res = solve_one(x)
        if res is None:
            out.append("-1")
        else:
            n, m = res
            out.append(f"{n} {m}")
    sys.stdout.write("\n".join(out))

