            else:
                dist[u] = INF
        found = False
        while q:
            u = q.popleft()
            for v in adj[u]:
                w = pairV[v]
                if w != -1:
                    if dist[w] == INF:
                        dist[w] = dist[u] + 1
                        q.append(w)
                else:
                    found = True
        return found

    def dfs(u):
        for v in adj[u]:
            w = pairV[v]
            if w == -1 or (dist[w] == dist[u] + 1 and dfs(w)):
                pairU[u] = v
                pairV[v] = u
                return True
        dist[u] = INF
        return False

    matching = 0
    while bfs():
        for u in range(N):
            if pairU[u] == -1 and dfs(u):
                matching += 1

