import sys

def count_upto(x, k):
    # count numbers in [0, x] with popcount == k
    if x < 0:
        return 0
    bits = []
    while x:
        bits.append(x & 1)
        x >>= 1
    # DP over bits from MSB to LSB
    # dp[pos][cnt][tight]
    from functools import lru_cache
    n = len(bits)
    @lru_cache(None)
    def dfs(pos, cnt, tight):
        if cnt > k:
            return 0
        if pos == -1:
            return 1 if cnt == k else 0
        limit = bits[pos] if tight else 1
        res = 0
        for b in range(limit+1):
            res += dfs(pos-1, cnt + b, tight and (b == limit))
        return res
    return dfs(n-1, 0, True)

def C(n, k):
    # count numbers in [0, n] with popcount == k
    return count_upto(n, k)

