import sys

def matches(pattern, s):
    m, n = len(pattern), len(s)
    dp = [[False] * (n + 1) for _ in range(m + 1)]
    dp[0][0] = True
    for i in range(m):
        ch = pattern[i]
        if ch == '*':
            # dp[i+1][0] = dp[i][0]
            dp[i+1][0] = dp[i][0]
            for j in range(1, n + 1):
                dp[i+1][j] = dp[i][j] or dp[i+1][j-1]
        else:
            for j in range(1, n + 1):
                dp[i+1][j] = dp[i][j-1] and (ch == s[j-1])
    return dp[m][n]

