def number_name(n):
    units = ["zero","one","two","three","four","five","six","seven","eight","nine"]
    if n < 10:
        return units[n]
    if n < 20:
        if n == 10:
            return "ten"
        teens = ["eleven","twelve","thirteen","fourteen","fifteen","sixteen","seventeen","eighteen","nineteen"]
        return teens[n-11]
    tens_words = {2:"twenty",3:"thirty",4:"forty",5:"fifty",6:"sixty",7:"seventy",8:"eighty",9:"ninety"}
    if n < 100:
        t = n // 10
        r = n % 10
        if r == 0:
            return tens_words[t]
        else:
            return tens_words[t] + units[r]
    # 100-999
    h = n // 100
    rem = n % 100
    hundreds = units[h] + "hundred"
    if rem == 0:
        return hundreds
    else:
        return hundreds + number_name(rem)

