MOD = 1000000007

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        print(0)
        return
    it = iter(data)
    n = int(next(it))
    a = [int(next(it)) for _ in range(n)]
    present = [False]*(n+1)
    for x in a:
        if x != -1:
            present[x] = True
    S = []
    for v in range(1, n+1):
        if not present[v]:
            S.append(v)
    m = len(S)
    # k = count of i such that a[i] == -1 and i in S
    inS = [False]*(n+1)
    for v in S:
        inS[v] = True
    k = 0
    for idx in range(1, n+1):
        if a[idx-1] == -1 and inS[idx]:
            k += 1

    # Precompute factorials
    maxn = n
    fact = [1]*(maxn+1)
    for i in range(1, maxn+1):
        fact[i] = fact[i-1]*i % MOD
    invfact = [1]*(maxn+1)
    invfact[maxn] = pow(fact[maxn], MOD-2, MOD)
    for i in range(maxn, 0, -1):
        invfact[i-1] = invfact[i]*i % MOD

    def comb(nr, rr):
        if rr < 0 or rr > nr:
            return 0
        return fact[nr]*invfact[rr]%MOD*invfact[nr-rr]%MOD

    ans = 0
    for t in range(0, k+1):
        term = comb(k, t) * fact[m - t] % MOD
        if t % 2 == 1:
            ans = (ans - term) % MOD
        else:
            ans = (ans + term) % MOD

    print(ans % MOD)

