import sys

class Dinic:
    class Edge:
        __slots__ = ('to','rev','cap')
        def __init__(self, to, rev, cap):
            self.to = to
            self.rev = rev
            self.cap = cap

    def __init__(self, N):
        self.N = N
        self.G = [[] for _ in range(N)]

    def add_edge(self, fr, to, cap):
        fwd = Dinic.Edge(to, len(self.G[to]), cap)
        rev = Dinic.Edge(fr, len(self.G[fr]), 0)
        self.G[fr].append(fwd)
        self.G[to].append(rev)

    def max_flow(self, s, t):
        flow = 0
        N = self.N
        INF = 10**9
        while True:
            level = [-1]*N
            q = []
            q.append(s)
            level[s] = 0
            for v in q:
                for e in self.G[v]:
                    if e.cap > 0 and level[e.to] < 0:
                        level[e.to] = level[v] + 1
                        q.append(e.to)
            if level[t] < 0:
                break
            it = [0]*N
            def dfs(v, upTo):
                if v == t:
                    return upTo
                for i in range(it[v], len(self.G[v])):
                    e = self.G[v][i]
                    if e.cap > 0 and level[v] < level[e.to]:
                        d = dfs(e.to, min(upTo, e.cap))
                        if d > 0:
                            e.cap -= d
                            self.G[e.to][e.rev].cap += d
                            return d
                    it[v] += 1
                return 0
            while True:
                f = dfs(s, INF)
                if f == 0:
                    break
                flow += f
        return flow

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it)); K = int(next(it)); M = int(next(it))
    edges = []
    for _ in range(M):
        a = int(next(it)); b = int(next(it))
        edges.append((a-1, b-1))
    # Build layered graph
    layers = N * K
    S = layers
    T = layers + 1
    din = Dinic(layers + 2)
    # Add transitions
    for (u, v) in edges:
        for r in range(K):
            from_id = u * K + r
            to_id = v * K + ((r + 1) % K)
            din.add_edge(from_id, to_id, 1)
    # Source to producer starts (j from 1..K, excluding j==N)
    base = 1 if N <= K else 0  # producers at N deliver directly
    for j in range(1, K+1):
        if j == N:
            continue
        node = (j-1) * K + ((j-1) % K)
        din.add_edge(S, node, 1)
    # Sinks: (N-1, r) -> T
    for r in range(K):
        din.add_edge((N-1) * K + r, T, 1)

    flow = din.max_flow(S, T)
    print(base + flow)

