import sys
import heapq

def dijkstra(n, adj, start):
    INF = 10**18
    dist = [INF] * (n + 1)
    dist[start] = 0
    h = [(0, start)]
    while h:
        d, u = heapq.heappop(h)
        if d != dist[u]:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd
                heapq.heappush(h, (nd, v))
    return dist

def main():
    data = list(map(int, sys.stdin.buffer.read().split()))
    if not data:
        return
    it = iter(data)
    n = next(it)
    m = next(it)
    adj = [[] for _ in range(n + 1)]
    for _ in range(m):
        a = next(it); b = next(it); t = next(it)
        adj[a].append((b, t))
        adj[b].append((a, t))
    balls = [next(it) for _ in range(7)]
    targets_set = set(balls)
    if 1 in targets_set:
        targets_set.discard(1)  # starting city collects any balls there
    targets = sorted(targets_set)
    k = len(targets)
    if k == 0:
        print(0)
        return

    INF = 10**18
    dist_start = dijkstra(n, adj, 1)
    dist_from_target = []
    for t in targets:
        dist_from_target.append(dijkstra(n, adj, t))

    dist_start_to = [dist_start[t] for t in targets]
    dist_between = [[0]*k for _ in range(k)]
    for i in range(k):
        for j in range(k):
            dist_between[i][j] = dist_from_target[i][targets[j]]

    # DP
    size = 1 << k
    dp = [[INF]*k for _ in range(size)]
    for i in range(k):
        if dist_start_to[i] < INF:
            dp[1<<i][i] = dist_start_to[i]

    for mask in range(size):
        for last in range(k):
            cur = dp[mask][last]
            if cur >= INF:
                continue
            for nxt in range(k):
                if (mask >> nxt) & 1:
                    continue
                d = dist_between[last][nxt]
                if d >= INF:
                    continue
                nmask = mask | (1 << nxt)
                nd = cur + d
                if nd < dp[nmask][nxt]:
                    dp[nmask][nxt] = nd

    full = size - 1
    ans = min(dp[full][i] for i in range(k))
    if ans >= INF:
        print(-1)
    else:
        print(ans)

if __name__ == "__main__":
    main()

import sys
import math

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it))
    circles = []
    for _ in range(n):
        x = int(next(it)); y = int(next(it)); r = int(next(it))
        circles.append((x, y, r))
    # build containment tree (forest)
    parent = [-1]*n
    # Precompute squared distances
    dist2 = [[0]*n for _ in range(n)]
    for i in range(n):
        xi, yi, ri = circles[i]
        for j in range(n):
            xj, yj, rj = circles[j]
            dx = xi - xj
            dy = yi - yj
            dist2[i][j] = dx*dx + dy*dy
    for j in range(n):
        best_parent = -1
        best_r = None
        for i in range(n):
            ri = circles[i][2]
            rj = circles[j][2]
            if ri >= rj:
                dx2 = dist2[i][j]
                # contains if distance <= ri - rj
                distsq = dx2
                diff = ri - rj
                if distsq <= diff*diff:
                    if best_parent == -1 or circles[i][2] < circles[best_parent][2]:
                        best_parent = i
        parent[j] = best_parent
    # build children lists
    children = [[] for _ in range(n)]
    roots = []
    for i in range(n):
        p = parent[i]
        if p != -1:
            children[p].append(i)
        else:
            roots.append(i)
    # compute DP
    area = [math.pi * (circles[i][2]**2) for i in range(n)]
    # postorder traversal
    sys.setrecursionlimit(1000000)
    dp = [[[0.0 for _ in range(2)] for _ in range(2)] for _ in range(n)]
    visited = [False]*n

    def dfs(u):
        for v in children[u]:
            dfs(v)
        # compute for all h in {0,1}, p in {0,1}
        for h in (0,1):
            for p in (0,1):
                val = ((-1.0)**p) * area[u]
                for v in children[u]:
                    # child can be in same half h with parity p^1, or other half 1-h with parity 0
                    same = dp[v][h][p^1]
                    other = dp[v][1-h][0]
                    val += max(same, other)
                dp[u][h][p] = val

    for r in roots:
        dfs(r)

    # result: max over roots r and h in {0,1} of dp[r][h][0]
    ans = 0.0
    for r in roots:
        for h in (0,1):
            ans = max(ans, dp[r][h][0])
    print("{:.10f}".format(ans))

if __name__ == "__main__":
    main()

