def min_swaps_to_good(n, arr):
    c0 = 0  # even index has odd value
    c1 = 0  # odd index has even value
    for i in range(n):
        if i % 2 == 0:
            if arr[i] % 2 == 1:
                c0 += 1
        else:
            if arr[i] % 2 == 0:
                c1 += 1
    if c0 != c1:
        return -1
    return c0

