import sys

def can_cover(T, stars, packs):
    m = len(stars)
    if m == 0:
        return True
    i = 0  # index in stars
    for p in packs:
        if i >= m:
            return True
        # if current star cannot be reached by this packman at all, skip this packman
        if abs(p - stars[i]) > T:
            continue
        # now try to cover as many as possible starting from stars[i]
        j = i
        # extend j as far as possible
        while j + 1 < m:
            left = stars[i]
            right = stars[j+1]
            needed = (right - left) + min(abs(p - left), abs(p - right))
            if needed <= T:
                j += 1
            else:
                break
        i = j + 1
        if i >= m:
            return True
    return i >= m

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])
    s = data[1].strip()
    stars = []
    packs = []
    for idx, ch in enumerate(s):
        if ch == '*':
            stars.append(idx)
        elif ch == 'P':
            packs.append(idx)
    # binary search minimal T
    lo, hi = 0, n  # inclusive hi
    while lo < hi:
        mid = (lo + hi) // 2
        if can_cover(mid, stars, packs):
            hi = mid
        else:
            lo = mid + 1
    print(lo)

